// src/pages/FarmDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
import speciesData from '../data/speciesData';

function FarmDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const [activityFormData, setActivityFormData] = useState({
    speciesName: '',        // Dữ liệu cuối cùng sẽ được gửi đi
    scientificName: '',   // Dữ liệu cuối cùng sẽ được gửi đi
    date: '',
    increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    reasonForChange: '',
  });

  // State để điều khiển giao diện
  const [selectedOldSpecies, setSelectedOldSpecies] = useState('');
  const [selectedNewSpecies, setSelectedNewSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  const fetchFarmDetails = useCallback(async () => {
    // ... logic fetchData giữ nguyên, nó sẽ setFarm và activities
  }, [farmId, token, navigate]);

  useEffect(() => {
    if (farmId && token) fetchFarmDetails();
  }, [farmId, token, navigate, fetchFarmDetails]);

  // --- CẬP NHẬT: Một hàm xử lý duy nhất cho toàn bộ form ---
  const handleChange = (e) => {
    const { name, value } = e.target;

    // Xử lý dropdown "Species Name (đã có)"
    if (name === 'oldSpeciesSelection') {
      setSelectedOldSpecies(value);
      setSelectedNewSpecies(''); // Reset lựa chọn mới
      setIsManualEntry(false);
      setActivityFormData(prev => ({...prev, speciesName: value, scientificName: ''}));
      return;
    }

    // Xử lý dropdown "Tên lâm sản mới"
    if (name === 'newSpeciesSelection') {
      setSelectedNewSpecies(value);
      setSelectedOldSpecies(''); // Reset lựa chọn cũ
      
      if (value === 'manual' || value === 'Nhập thủ công') {
        setIsManualEntry(true);
        setActivityFormData(prev => ({...prev, speciesName: '', scientificName: ''}));
      } else {
        setIsManualEntry(false);
        const matched = speciesData.find(s => s.tenLamSan === value);
        setActivityFormData(prev => ({
          ...prev,
          speciesName: matched ? matched.tenLamSan : '',
          scientificName: matched ? matched.tenKhoaHoc : ''
        }));
      }
      return;
    }

    // Xử lý các input lồng nhau (increase/decrease)
    if (name.includes('.')) {
      const [mainField, subField, prop] = name.split('.');
      setActivityFormData(prev => ({
        ...prev,
        [mainField]: { ...prev[mainField], [subField]: { ...prev[mainField][subField], [prop]: parseInt(value, 10) || 0 } },
      }));
    } else {
      // Xử lý các input thông thường (date, reason, và các ô nhập tay)
      setActivityFormData(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleAddActivity = async (e) => {
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // Logic gửi đi không thay đổi nhiều, vì activityFormData đã chứa dữ liệu đúng
      const dataToSend = { ...activityFormData, farm: farmId };
      await axios.post(`http://localhost:10000/api/farm-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('Thêm bản ghi thành công!');
      fetchFarmDetails(); // Tải lại dữ liệu
      // Reset form
      setActivityFormData({
        speciesName: '', scientificName: '', date: '',
        increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
        reasonForChange: '',
      });
      setSelectedOldSpecies('');
      setSelectedNewSpecies('');
      setIsManualEntry(false);
    } catch (err) {
      setError(err.response?.data?.message || 'Thêm bản ghi thất bại.');
    }
  };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;
  if (error) return <div className="form-container"><p style={{ color: 'red' }}>Lỗi: {error}</p></div>;
  if (!farm) return <div className="form-container"><p>Không tìm thấy thông tin.</p></div>;

  return (
    <div className="form-container">
      <h2>👁️ Logbook: {farm.tenCoSo}</h2>
      
      <h3>Add New Tracking Record:</h3>
      {message && <div className="success-message">{message}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        
        <div className="form-group detail-group">
          <label>Species Name (đã có):</label>
          <select name="oldSpeciesSelection" value={selectedOldSpecies} onChange={handleChange}>
            <option value="">-- Select species --</option>
            {farm.loaiDongVatRung && farm.loaiDongVatRung.map((species, index) => (
              <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
            ))}
          </select>
        </div>

        <div className="form-group-full-width" style={{ border: '1px dashed #007bff', padding: '15px', borderRadius: '8px', marginBottom: '15px' }}>
          <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '10px', color: '#007bff' }}>
            Hoặc đăng ký lâm sản mới
          </label>
          <div className="form-grid">
            <div className="form-group">
              <label htmlFor="newSpeciesSelection">Tên lâm sản mới:</label>
              <select id="newSpeciesSelection" name="newSpeciesSelection" value={selectedNewSpecies} onChange={handleChange}>
                <option value="">-- Chọn hoặc nhập thủ công --</option>
                {speciesData.map((species, index) => (
                  <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
                ))}
              </select>
            </div>
            {!isManualEntry && selectedNewSpecies && !selectedNewSpecies.includes("thủ công") && (
              <div className="form-group">
                <label>Tên khoa học (tự động):</label>
                <input type="text" value={activityFormData.scientificName} readOnly disabled />
              </div>
            )}
            {isManualEntry && (
              <>
                <div className="form-group">
                  <label>Tên loài (nhập tay):</label>
                  <input type="text" name="speciesName" value={activityFormData.speciesName} onChange={handleChange} required />
                </div>
                <div className="form-group">
                  <label>Tên khoa học (nhập tay):</label>
                  <input type="text" name="scientificName" value={activityFormData.scientificName} onChange={handleChange} />
                </div>
              </>
            )}
          </div>
        </div>
        
        <div className="form-grid">
          <div className="form-group">
            <label>Date Recorded:</label>
            <input type="date" name="date" value={activityFormData.date} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label>Reason for Change:</label>
            <input type="text" name="reasonForChange" value={activityFormData.reasonForChange} onChange={handleChange} />
          </div>
        </div>

        {/* ... Phần Increase / Decrease giữ nguyên ... */}
        
        <button type="submit" className="submit-button">Add Record</button>
      </form>

      <h3>Tracking History:</h3>
      {/* ... Bảng hiển thị giữ nguyên ... */}
    </div>
  );
}

export default FarmDetail;
